            for (const part of parts) {
                const lines = part.value.split('\n');
                if (lines.length && lines[lines.length - 1] === '') {
                    lines.pop();
                }
                if (!lines.length) {
                    continue;
                }
                if (part.added) {
                    for (const line of lines) {
                        leftRendered.push(`<div class="diff-row empty"><span class="line-no"></span><span class="line-text">&nbsp;</span></div>`);
                        rightRendered.push(`<div class="diff-row add"><span class="line-no">${rightLineNo}</span><span class="line-text">${escapeHtml(line) || '&nbsp;'}</span></div>`);
                        rightLineNo += 1;
                    }
                    continue;
                }
                if (part.removed) {
                    for (const line of lines) {
                        leftRendered.push(`<div class="diff-row del"><span class="line-no">${leftLineNo}</span><span class="line-text">${escapeHtml(line) || '&nbsp;'}</span></div>`);
                        rightRendered.push(`<div class="diff-row empty"><span class="line-no"></span><span class="line-text">&nbsp;</span></div>`);
                        leftLineNo += 1;
